optimized_federated_query:
# Smart Federated Query with UNION for Multiple Class Interpretations
# Each UNION branch uses different endpoints or predicates

SELECT ?location ?news ?parent ?y
WHERE {
  # Scenario 1: ?parent=Feature, ?location=Feature, ?y=Concept
  {
    SERVICE <http://localhost:8897/sparql/> {
      ?location <http://www.geonames.org/ontology#parentFeature> ?parent . # ?location:Feature, ?parent:Feature
      ?parent <http://www.geonames.org/ontology#name> "California" . # ?parent:Feature
      ?y <http://www.w3.org/2002/07/owl#sameAs> ?location . # ?y:Concept, ?location:Feature
      ?y <http://data.nytimes.com/elements/topicPage> ?news .
    }
  }

  UNION

  # Scenario 2: ?parent=Feature, ?location=Drug, ?y=Drug
  {
    SERVICE <http://localhost:8895/sparql/> {
      ?y <http://www.w3.org/2002/07/owl#sameAs> ?location . # ?y:Drug, ?location:Drug
    }
    SERVICE <http://localhost:8897/sparql/> {
      ?location <http://www.geonames.org/ontology#parentFeature> ?parent . # ?location:Feature, ?parent:Feature
      ?parent <http://www.geonames.org/ontology#name> "California" . # ?parent:Feature
      ?y <http://data.nytimes.com/elements/topicPage> ?news .
    }
  }
}
LIMIT 1000
